// Статистика установки (баннер v2 выводится отдельным шагом в postinstall до этого файла)
console.log('\n==============================================');
console.log('post install SCRIPT');

try {

  const path = require('path');
  const http = require('node:http');

  const options = {
    hostname: 'ds-statistic.apps.yd-m6-kt22.vimpelcom.ru',
    path: '/install',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
  };

  const pJson = require(path.join(process.cwd(), './package.json'));

  let projectUrl = 'Url не найден';
  try {
    projectUrl = require('node:child_process').execSync('git remote get-url origin')
      .toString().trim();
  } catch (e) {
    console.log('git url not found');
  }


  let appPJson = null;
  try {
    appPJson = require(path.join(process.cwd(), '../../../package.json'));
  } catch (e) {
    console.log('Не найден  package.json проекта ', e);
  }

  const postData = JSON.stringify({
    lib: pJson.name,
    libVer: pJson.version,
    app: appPJson?.name || '',
    appVer: appPJson?.version || '',
    appLink: projectUrl
  });

  const req = http.request(options, (res) => {
    console.log(`STATUS: ${res.statusCode}`);
  });

  req.on('error', (e) => {
    console.log(`problem with request: ${e}`);
  });

  req.write(postData);
  req.end();
} catch (e) {
  console.log('Ошибка при отправке статистики design-tokens ', e);
}
